#!/usr/bin/env python3
"""Heuristic exploration planner: greedy utility + global BFS."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

class HeuristicPlanner:
    def __init__(self, epsilon=0.05):
        self.epsilon = epsilon
        self.nodes_coords = []
        self.coord_to_idx = {}
        self.adj = []
        self.n_nodes = 0

    def reset(self, nodes):
        self.n_nodes = len(nodes)
        self.nodes_coords = []
        self.coord_to_idx.clear()
        for i, nd in enumerate(nodes):
            x = float(nd['coords'][0])
            y = float(nd['coords'][1])
            self.nodes_coords.append((x, y))
            self.coord_to_idx[(x, y)] = i
        self.adj = [[] for _ in range(self.n_nodes)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = (float(nb[0]), float(nb[1]))
                j = self.coord_to_idx.get(key, -1)
                if j >= 0 and j != i:
                    if j not in self.adj[i]:
                        self.adj[i].append(j)
                    if i not in self.adj[j]:
                        self.adj[j].append(i)

    def bfs_path(self, start_idx, target_idx):
        n = self.n_nodes
        parent = [-1] * n
        q = deque([start_idx])
        visited = [False] * n
        visited[start_idx] = True
        while q:
            u = q.popleft()
            if u == target_idx:
                break
            for v in self.adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    q.append(v)
        return parent

    def reconstruct_path(self, start_idx, target_idx, parent):
        if target_idx < 0 or target_idx >= self.n_nodes:
            return []
        if parent[target_idx] == -1 and start_idx != target_idx:
            return []
        path = []
        cur = target_idx
        for _ in range(self.n_nodes):
            if cur == start_idx:
                break
            path.append(cur)
            cur = parent[cur]
            if cur == -1:
                break
        path.reverse()
        return path

    def get_closest_node_idx(self, pos):
        best_idx = -1
        best_dist = float('inf')
        for i, coord in enumerate(self.nodes_coords):
            d = euclidean(pos, coord)
            if d < best_dist:
                best_dist = d
                best_idx = i
        return best_idx

    def select_action(self, obs, curr_idx, tabu_set):
        neighbor_coords = obs.get('neighbors', [])
        neighbor_idxs = []
        for nb in neighbor_coords:
            key = (float(nb[0]), float(nb[1]))
            i = self.coord_to_idx.get(key, -1)
            if i >= 0:
                neighbor_idxs.append(i)
        if not neighbor_idxs:
            return None

        node_utils = [nd['utility'] for nd in obs['nodes']]
        if len(node_utils) != self.n_nodes:
            valid = [i for i in neighbor_idxs if i not in tabu_set]
            if not valid:
                valid = neighbor_idxs
            i = random.choice(valid)
            return self.nodes_coords[i]

        # 1) greedy neighbor with max utility > 0, not tabu
        best_util = -1
        best_idx = -1
        for ni in neighbor_idxs:
            if ni in tabu_set:
                continue
            u = node_utils[ni]
            if u > best_util:
                best_util = u
                best_idx = ni
        if best_util > 0 and best_idx >= 0:
            return self.nodes_coords[best_idx]

        # 2) epsilon-random exploration
        if random.random() < self.epsilon:
            valid = [i for i in neighbor_idxs if i not in tabu_set]
            if not valid:
                valid = neighbor_idxs
            i = random.choice(valid)
            return self.nodes_coords[i]

        # 3) global BFS to max utility node (excluding current)
        global_best = -1
        global_best_util = -1
        for i, u in enumerate(node_utils):
            if u > global_best_util and i != curr_idx:
                global_best_util = u
                global_best = i
        if global_best >= 0:
            parent = self.bfs_path(curr_idx, global_best)
            path = self.reconstruct_path(curr_idx, global_best, parent)
            if path and path[0] in neighbor_idxs:
                return self.nodes_coords[path[0]]

        valid = [i for i in neighbor_idxs if i not in tabu_set]
        if not valid:
            valid = neighbor_idxs
        i = random.choice(valid)
        return self.nodes_coords[i]


def run_episode(env, planner):
    obs = env.reset()
    planner.reset(obs['nodes'])
    total_dist = 0.0
    steps = 0
    prev_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))
    curr_idx = planner.get_closest_node_idx(prev_pos)
    tabu = deque(maxlen=3)
    while steps < 128:
        target = planner.select_action(obs, curr_idx, set(tabu))
        if target is None:
            break
        obs, info = env.step(target)
        steps += 1
        new_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))
        dist = euclidean(prev_pos, new_pos)
        total_dist += dist
        prev_pos = new_pos
        new_idx = planner.get_closest_node_idx(new_pos)
        tabu.append(curr_idx)
        curr_idx = new_idx
        if info.get('done', False):
            break
    metrics = env.get_metrics()
    return {
        'success': int(metrics.get('success', False)),
        'explored_rate': float(metrics['explored_rate']),
        'travel_distance': total_dist,
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(config_path, 'r') as f:
        eval_cfg = json.load(f)

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    map_paths = []
    for rt, dirs, files in os.walk(maps_dir):
        for fn in files:
            if fn.endswith('.png'):
                map_paths.append(os.path.join(rt, fn))
    map_paths.sort()

    random.seed(42)
    planner = HeuristicPlanner(epsilon=0.05)

    per_episode = []
    per_type = {}
    type_stats = {}
    for t in eval_cfg['env_types']:
        type_stats[t] = {'success': 0, 'explored_rate': [], 'travel_distances': [], 'n': 0}

    total_success = 0
    total_explored = 0.0
    total_dist_success = 0.0
    n_episodes = len(map_paths)

    for mp in map_paths:
        rel = os.path.relpath(mp, maps_dir)
        env_type = rel.split(os.sep)[0] if os.sep in rel else 'unknown'
        env = ExplorationEnv(map_path=mp)
        res = run_episode(env, planner)
        per_episode.append({
            'map_path': rel,
            'env_type': env_type,
            'success': res['success'],
            'travel_distance': res['travel_distance'],
            'explored_rate': res['explored_rate'],
        })
        total_explored += res['explored_rate']
        if res['success']:
            total_success += 1
            total_dist_success += res['travel_distance']
        if env_type in type_stats:
            ts = type_stats[env_type]
            ts['n'] += 1
            ts['explored_rate'].append(res['explored_rate'])
            if res['success']:
                ts['success'] += 1
                ts['travel_distances'].append(res['travel_distance'])

    explored_rate_avg = total_explored / n_episodes if n_episodes else 0.0
    success_rate = total_success / n_episodes if n_episodes else 0.0
    travel_distance_avg = total_dist_success / total_success if total_success > 0 else 0.0

    per_type_out = {}
    for t in eval_cfg['env_types']:
        ts = type_stats[t]
        n = ts['n']
        if n == 0:
            per_type_out[t] = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0}
            continue
        er = sum(ts['explored_rate']) / n
        success_frac = ts['success'] / n
        if ts['travel_distances']:
            d_avg = sum(ts['travel_distances']) / len(ts['travel_distances'])
        else:
            d_avg = 0.0
        per_type_out[t] = {
            'explored_rate': er,
            'travel_distance': d_avg,
            'success_rate': success_frac,
        }

    result = {
        'explored_rate': explored_rate_avg,
        'travel_distance': travel_distance_avg,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': n_episodes,
    }

    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

if __name__ == '__main__':
    main()
